       },
     ],
   };

   const toolResultMessage: ChatCompletionMessage = {
     role: "tool",
     tool_call_id: "call_abc123",
     content: "It is raining.",
   };

   const subsequentAssistantMessage: ChatCompletionMessage = {
     role: "assistant",
     content: "It's raining in Boston.",
   };

   clientMock.chat.completions.create.mockResolvedValue({
     choices: [
       {
         message: subsequentAssistantMessage,
         finish_reason: "stop",
         index: 0,
         logprobs: null,
       },
     ],
     created: 0,
     id: "123",
     model: "gpt-3.5-turbo",
     object: "chat.completion",
   });

   // when
   const response = await executeOnTools(clientMock, message, {}, (_) => toolResultMessage);

   // then
   expect(response).toEqual(subsequentAssistantMessage);
   expect(clientMock.chat.completions.create).toBeCalledTimes(1);
   expect(clientMock.chat.completions.create).toBeCalledWith({
     messages: [
       {
         role: "assistant",
         content: "Old McDonald had a farm.\nE I E I O.",
         tool_calls: [
           {
             id: "call_abc123",
             type: "function",
             function: { name: "get_rainfall", arguments: '{"city":"Boston"}' },
           },
         ],
       },
       {
         role: "tool",
         tool_call_id: "call_abc123",
         content: "It is raining.",
       },
     ],
     model: "gpt-3.5-turbo",
     stream: false,
   });
 });

